      const bestSellers = products.filter(p => p.stock > 0).slice(0, 8)
      expect(newArrivals).toHaveLength(2)
      expect(featured).toHaveLength(2)
      expect(bestSellers).toHaveLength(3)
    })

    it("extracts unique brands", () => {
