        { id: "interior", name: "Interior", fee: 40000 },
        { id: "pickup", name: "Retiro en local", fee: 0 },
      ]
      expect(defaultZones).toHaveLength(4)
      expect(defaultZones.find(z => z.id === "pickup")!.fee).toBe(0)
